export default function updateTocScroll(t){const e=t.tocScrollingWrapper||t.tocElement||document.querySelector(t.tocSelector);if(e&&e.scrollHeight>e.clientHeight){const o=e.querySelector(`.${t.activeListItemClass}`);if(o){const c=o.offsetTop-t.tocScrollOffset;e.scrollTop=c>0?c:0}}}
